INSERT INTO observations (id, team_id, person_id, recorded_by, raw_text, domain, observed_at, recorder_role, confidence, confidence_score, parsed_json) VALUES
  ('00000000-0000-0000-0005-000000000001', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000001', 'Struggled with CVC blending but got 3/5 with picture cards, up from 1/5 without.', 'literacy', NOW() - INTERVAL '26 days', 'teacher', 'HIGH', 4, '{"students":[],"context":"literacy","skills":["phonics"],"methods":[{"key":"visual","label":"Visual / Picture cues","negated":false,"source":"auto"}],"outcome":"mixed","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":[],"methods":[]},"evidence":{"skills":{"phonics":{"trigger":"cvc","match":"cvc"}},"methods":{"visual":{"trigger":"picture card","match":"picture cards","negated":false}},"outcome":[{"word":"struggled","trigger":"struggled","negated":false,"polarity":"negative"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000002', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000001', 'Decoded 8 of 10 sounds independently today — big jump from last week.', 'literacy', NOW() - INTERVAL '19 days', 'teacher', 'HIGH', 4, '{"students":[],"context":"literacy","skills":[],"methods":[{"key":"independent","label":"Independent practice","negated":false,"source":"auto"}],"outcome":"positive","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":["phonics","gross_motor","independence"],"methods":[]},"evidence":{"skills":{},"methods":{"independent":{"trigger":"independently","match":"independently","negated":false}},"outcome":[{"word":"independently","trigger":"independently","negated":false,"polarity":"positive"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000003', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000002', 'Used counters for counting to 20 and got all correct, her first time independently.', 'maths', NOW() - INTERVAL '12 days', 'ta', 'HIGH', 4, '{"students":[],"context":"maths","skills":["counting"],"methods":[{"key":"independent","label":"Independent practice","negated":false,"source":"auto"}],"outcome":"positive","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":["independence"],"methods":[{"key":"kinesthetic","label":"Hands-on / Manipulatives","negated":false}]},"evidence":{"skills":{"counting":{"trigger":"counting to","match":"counting to"}},"methods":{"independent":{"trigger":"independently","match":"independently","negated":false}},"outcome":[{"word":"independently","trigger":"independently","negated":false,"polarity":"positive"},{"word":"correct","trigger":"correct","negated":false,"polarity":"positive"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000004', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000001', 'Raised her hand to ask for help during small group reading.', 'social', NOW() - INTERVAL '8 days', 'teacher', 'HIGH', 3, '{"students":[],"context":"social","skills":["communication"],"methods":[{"key":"small_group","label":"Small group","negated":false,"source":"auto"}],"outcome":"unknown","confidence":"HIGH","confidenceScore":3,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":3,"suggestions":{"skills":[],"methods":[]},"evidence":{"skills":{"communication":{"trigger":"raised her hand","match":"raised her hand"}},"methods":{"small_group":{"trigger":"small group","match":"small group","negated":false}},"outcome":[]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000005', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000004', 'Stayed calm through transitions and used her coping strategy independently this time.', 'behaviour', NOW() - INTERVAL '5 days', 'specialist', 'HIGH', 4, '{"students":[],"context":"behaviour","skills":["self_regulation"],"methods":[{"key":"independent","label":"Independent practice","negated":false,"source":"auto"}],"outcome":"positive","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":["independence","problem_solving"],"methods":[]},"evidence":{"skills":{"self_regulation":{"trigger":"coping strategy","match":"coping strategy"}},"methods":{"independent":{"trigger":"independently","match":"independently","negated":false}},"outcome":[{"word":"independently","trigger":"independently","negated":false,"polarity":"positive"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000006', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000001', '00000000-0000-0000-0003-000000000001', 'Read the passage and answered comprehension questions correctly with one-on-one support.', 'literacy', NOW() - INTERVAL '2 days', 'teacher', 'HIGH', 4, '{"students":[],"context":"literacy","skills":["reading_comprehension","reading"],"methods":[{"key":"one_on_one","label":"1-on-1 support","negated":false,"source":"auto"}],"outcome":"positive","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":[],"methods":[]},"evidence":{"skills":{"reading_comprehension":{"trigger":"comprehension","match":"comprehension"},"reading":{"trigger":"read the passage","match":"read the passage"}},"methods":{"one_on_one":{"trigger":"one-on-one","match":"one-on-one","negated":false}},"outcome":[{"word":"correctly","trigger":"correctly","negated":false,"polarity":"positive"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000007', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000002', '00000000-0000-0000-0003-000000000001', 'Blended 4 of 5 words but struggled to focus in group work.', 'literacy', NOW() - INTERVAL '24 days', 'teacher', 'HIGH', 4, '{"students":[],"context":"literacy","skills":[],"methods":[{"key":"small_group","label":"Small group","negated":false,"source":"auto"}],"outcome":"mixed","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":["phonics"],"methods":[]},"evidence":{"skills":{},"methods":{"small_group":{"trigger":"group work","match":"group work","negated":false}},"outcome":[{"word":"struggled","trigger":"struggled","negated":false,"polarity":"negative"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000008', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000002', '00000000-0000-0000-0003-000000000001', 'Struggled with number sense and could not complete the number line.', 'maths', NOW() - INTERVAL '17 days', 'teacher', 'HIGH', 4, '{"students":[],"context":"maths","skills":[],"methods":[{"key":"visual","label":"Visual / Picture cues","negated":true,"source":"auto"}],"outcome":"negative","confidence":"HIGH","confidenceScore":4,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":4,"suggestions":{"skills":["number_recognition"],"methods":[]},"evidence":{"skills":{},"methods":{"visual":{"trigger":"number line","match":"number line","negated":true}},"outcome":[{"word":"struggled","trigger":"struggled","negated":false,"polarity":"negative"},{"word":"could not","trigger":"could not","negated":false,"polarity":"negative"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000009', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000002', '00000000-0000-0000-0003-000000000004', 'Refused to share materials and had a meltdown during transition.', 'behaviour', NOW() - INTERVAL '10 days', 'specialist', 'HIGH', 3, '{"students":[],"context":"behaviour","skills":["self_regulation"],"methods":[],"outcome":"negative","confidence":"HIGH","confidenceScore":3,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":3,"suggestions":{"skills":["sharing_cooperation"],"methods":[]},"evidence":{"skills":{"self_regulation":{"trigger":"meltdown","match":"meltdown"}},"methods":{},"outcome":[{"word":"refused","trigger":"refused","negated":false,"polarity":"negative"}]},"lexicon":"1.4"}'),
  ('00000000-0000-0000-0005-000000000010', '00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0004-000000000002', '00000000-0000-0000-0003-000000000001', 'Tried again after a verbal prompt and figured out the problem.', 'literacy', NOW() - INTERVAL '3 days', 'teacher', 'HIGH', 3, '{"students":[],"context":"literacy","skills":["problem_solving"],"methods":[{"key":"verbal_prompt","label":"Verbal prompt / Cue","negated":false,"source":"auto"}],"outcome":"unknown","confidence":"HIGH","confidenceScore":3,"flags":["no_student_matched"],"llmFallbackSuggested":false,"signalStrength":3,"suggestions":{"skills":[],"methods":[]},"evidence":{"skills":{"problem_solving":{"trigger":"figured out","match":"figured out"}},"methods":{"verbal_prompt":{"trigger":"verbal prompt","match":"verbal prompt","negated":false}},"outcome":[]},"lexicon":"1.4"}'),
